import logo from './logo.svg';
import './App.css';
import 'bootstrap/dist/css/bootstrap.min.css'
import {Container, InputGroup, FormControl, Button, Pagination} from 'react-bootstrap'
import {useState, useEffect} from 'react'
import ReactPaginate from 'react-paginate';
import axios from 'axios';
import SpoitfyWebApi from 'spotify-web-api-js'

function App() {
  //Spotify Web API JS
  const spotify = new SpoitfyWebApi();

  //Account Authorization
  const REDIRECT_URI = "http://localhost:3000"
  const AUTH_ENDPOINT = "https://accounts.spotify.com/authorize"
  const RESPONSE_TYPE = "token"

  const scopes = [
  "playlist-read-private",
  "playlist-read-collaborative"
  ]

  //Setting up use states
  const [token, setToken] = useState("")
  const [searchKey, setSearchKey] = useState("")
  const [artists, setArtists] = useState([])  
  const [spotifyToken, setSpotifyToken] = useState("")

  //Credit: https://github.com/dom-the-dev/spotify-with-react
  //
  useEffect(() => {
    //Getting access token from account authorization
    const hash = window.location.hash
    let token = window.localStorage.getItem("token")

    if (!token && hash) {
        token = hash.substring(1).split("&").find(elem => elem.startsWith("access_token")).split("=")[1]

        window.location.hash = ""
        window.localStorage.setItem("token", token)
    }

    setToken(token)

    //Authorizing with Spotify API via Spotify Web API JS
    if (token) {
      spotify.setAccessToken(token)
      spotify.getMe().then((user) => {
        console.log("USER: ", user)
      })
    }
}, [])

  const logout = () => {
    setToken("")
    window.localStorage.removeItem("token")
  }

  const searchArtists = async (e) => {
    e.preventDefault()
    const {data} = await axios.get("https://api.spotify.com/v1/search", {
        headers: {
            Authorization: `Bearer ${token}`
        },
        params: {
            q: searchKey,
            type: "artist"
        }
    })

    setArtists(data.artists.items)
}
//

  const items = [...Array(33).keys()];

  function Items({ currentItems }) {
    return (
      <div className="items">
      {currentItems && currentItems.map((item) => (
        <div>
          <h3>Item #{item}</h3>
        </div>
      ))}
        </div>
    );
  }

  function PaginatedItems({ itemsPerPage }) {
    // We start with an empty list of items.
    const [currentItems, setCurrentItems] = useState(null);
    const [pageCount, setPageCount] = useState(0);
    // Here we use item offsets; we could also use page offsets
    // following the API or data you're working with.
    const [itemOffset, setItemOffset] = useState(0);

    useEffect(() => {
      // Fetch items from another resources.
      const endOffset = itemOffset + itemsPerPage;
      console.log(`Loading items from ${itemOffset} to ${endOffset}`);
      setCurrentItems(items.slice(itemOffset, endOffset));
      setPageCount(Math.ceil(items.length / itemsPerPage));
    }, [itemOffset, itemsPerPage]);

    // Invoke when user click to request another page.
    const handlePageClick = (event) => {
      const newOffset = event.selected * itemsPerPage % items.length;
      console.log(`User requested page number ${event.selected}, which is offset ${newOffset}`);
      setItemOffset(newOffset);
    };

    return (
      <>
        <Items currentItems={currentItems} />
        <ReactPaginate
          nextLabel="next >"
          onPageChange={handlePageClick}
          pageRangeDisplayed={3}
          marginPagesDisplayed={2}
          pageCount={pageCount}
          previousLabel="< previous"
          pageClassName="page-item"
          pageLinkClassName="page-link"
          previousClassName="page-item"
          previousLinkClassName="page-link"
          nextClassName="page-item"
          nextLinkClassName="page-link"
          breakLabel="..."
          breakClassName="page-item"
          breakLinkClassName="page-link"
          containerClassName="pagination"
          activeClassName="active"
          renderOnZeroPageCount={null}
        />
      </>
    );
  }

  async function search() {

  }

  return (
    <div className="App">
      <Container>
        <header className="App-header">
          <h1>Spotify Venn</h1>
                  {!token ?
                      <a href={`${AUTH_ENDPOINT}?client_id=${process.env.REACT_APP_CLIENT_ID}&redirect_uri=${REDIRECT_URI}&response_type=${RESPONSE_TYPE}&show_dialog=true`}>Login
                      to Spotify</a>
                  : <button onClick={logout}>Logout</button>}

                  {token ?
                      <InputGroup className="mb-3" size="lg">
                      <FormControl
                        placeholder = "Search for User"
                        type = "input"
                        onKeyDown={(Event) => {
                          if (Event.key == "Enter") {
                            search();
                          }
                        }}
                        //onChange={(Event) => setSearchInput(Event.target.value)}
                      />
                      <Button onClick = {(Event) => search()}>
                        Search
                      </Button>
                    </InputGroup>

                      : <h2>Please login</h2>
                  }
        </header>
      </Container>
      <Container>
        <div class = "pagination">

          <PaginatedItems itemsPerPage={4} class="pagination-centered" className="mb-3" size="lg"/>
        </div>
      </Container>
    </div>
  );
}

export default App;
